'use strict'

/**
 * Module exports.
 * @public
 */

module.exports = depd

/**
 * Display a deprecation message in the browser.
 *
 * @param {string} message
 * @param {object} [options]
 * @return {void}
 * @public
 */

function depd(message, options) {
  var opts = options || {}
  var header = opts.header || defaultHeader

  // Format the message
  var formattedMessage = header + ' ' + message

  // Attempt to get the stack trace
  var stack = getStack()
  
  // Log to console with stack trace if available
  if (stack && stack.length) {
    var callSite = getCallSite(stack)
    if (callSite) {
      console.warn(formattedMessage + '\n    at ' + callSite)
      return
    }
  }
  
  // Fallback to simple warning
  console.warn(formattedMessage)
}

/**
 * Default deprecation header.
 */

var defaultHeader = 'DeprecationWarning:'

/**
 * Get call site location from stack.
 * 
 * @param {Array} stack
 * @return {string}
 * @private
 */

function getCallSite(stack) {
  // Find first external frame
  var frame
  for (var i = 0; i < stack.length; i++) {
    frame = stack[i]
    
    // Skip frames from depd itself
    if (frame.indexOf('depd') !== -1) {
      continue
    }
    
    return frame
  }
  
  return undefined
}

/**
 * Get stack trace as array.
 * 
 * @return {Array}
 * @private
 */

function getStack() {
  // Create an Error for stack trace
  var obj = new Error()
  
  // Parse the stack trace
  var stack = obj.stack
  
  if (!stack) {
    return undefined
  }
  
  // Split the stack by lines and remove the Error message line
  var lines = stack.split('\n').slice(1)
  
  // Clean up each line
  return lines.map(function(line) {
    return line.trim()
      .replace(/^at /, '')  // Remove 'at ' prefix
      .replace(/\s+\(.+\)$/, '')  // Remove source location
  })
}